/**
 * Generate Bubblemaps firewall config.
 *
 * Data source: https://docs.bubblemaps.io/data/api/authentication
 *
 * Bubblemaps authenticates with an API key passed in the X-ApiKey header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.bubblemaps.io/data/api/authentication";
const PLACEHOLDER_VALUE = "Coffee5afe10ca1Coffee5afe10ca1Co";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Bubblemaps API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:bubblemaps",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const bubblemapsFirewall = {",
    '  name: "bubblemaps",',
    '  description: "Bubblemaps Data API",',
    "  placeholders: {",
    `    BUBBLEMAPS_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.bubblemaps.io",',
    "      auth: {",
    "        headers: {",
    '          "X-ApiKey": "${{ secrets.BUBBLEMAPS_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Bubblemaps firewall config...");
  const ts = generateTypeScript();
  writeOutput("bubblemaps", ts, import.meta.dirname);
}
